import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';

// Components
import LandingPage from './LandingPage/LandingPage';
import Login from './components/auth/Login';
import Register from './components/auth/Register';
import ForgotPassword from './components/auth/ForgotPassword';
import ResetPassword from './components/auth/ResetPassword';
import OnboardingRoute from './components/auth/OnboardingRoute';
import MainDashboard from './dashboard/MainDashboard';
import AdminSandbox from './admin/AdminSandbox';
import RouteGuard from './components/auth/RouteGuard';

import LoadingSpinner from './components/LoadingSpinner';
import OfflineIndicator from './components/OfflineIndicator';

// Context
import { AuthProvider, useAuth } from './contexts/AuthContext';
import { AgentProvider } from './contexts/AgentContext';
import { ChatProvider } from './contexts/ChatContext';
import { OrchestratorProvider } from './contexts/OrchestratorContext';

// Styles

// Auth Container Component
const AuthContainer = ({ children }) => (
  <div className="auth-container">
    {children}
  </div>
);

// Auth Card Component  
const AuthCard = ({ children }) => (
  <div className="auth-card">
    {children}
  </div>
);

// Enhanced Private Route Component with strict validation
const PrivateRoute = ({ children }) => {
  const { user, loading } = useAuth();

  if (loading) {
    return (
      <AuthContainer>
        <LoadingSpinner />
      </AuthContainer>
    );
  }

  // Strict validation: user must exist and be authenticated
  if (!user) {
    return <Navigate to="/login" replace />;
  }

  // Additional validation: check for valid token
  const token = localStorage.getItem('access_token') || getCookie('access_token');
  if (!token) {
    return <Navigate to="/login" replace />;
  }

  // Validate token format and expiration
  try {
    const payload = JSON.parse(atob(token.split('.')[1]));
    if (payload.exp * 1000 < Date.now()) {
      return <Navigate to="/login" replace />;
    }
  } catch (error) {
    return <Navigate to="/login" replace />;
  }

  return <RouteGuard>{children}</RouteGuard>;
};

// Helper function to get cookie value
const getCookie = (name) => {
  const value = `; ${document.cookie}`;
  const parts = value.split(`; ${name}=`);
  if (parts.length === 2) return parts.pop().split(';').shift();
  return null;
};

// Main App Component
const AppContent = () => {
  const { user, loading, needsOnboarding } = useAuth();

  if (loading) {
    return (
      <AuthContainer>
        <LoadingSpinner />
      </AuthContainer>
    );
  }

  // Strict authentication validation
  if (!user) {
    return (
      <AuthContainer>
        <AuthCard>
          <Routes>
            <Route path="/login" element={<Login />} />
            <Route path="/register" element={<Register />} />
            <Route path="/forgot-password" element={<ForgotPassword />} />
            <Route path="/reset-password" element={<ResetPassword />} />
            <Route path="*" element={<Navigate to="/login" />} />
          </Routes>
        </AuthCard>
      </AuthContainer>
    );
  }

  // Validate token exists and is not expired
  const token = localStorage.getItem('access_token') || getCookie('access_token');
  if (!token) {
    return <Navigate to="/login" replace />;
  }

  try {
    const payload = JSON.parse(atob(token.split('.')[1]));
    if (payload.exp * 1000 < Date.now()) {
      return <Navigate to="/login" replace />;
    }
  } catch (error) {
    return <Navigate to="/login" replace />;
  }

  // Handle onboarding redirect
  if (needsOnboarding) {
    return <Navigate to="/onboarding" replace />;
  }

  // Role-based routing
  if ((user?.role || "").toLowerCase() === "admin") {
    return <Navigate to="/admin" replace />;
  }

  return <Navigate to="/dashboard" replace />;
};

// Root App Component
function App() {
  return (
    <AuthProvider>
      <OfflineIndicator />
      <OrchestratorProvider>
        <AgentProvider>
          <ChatProvider>
            <Routes>
              {/* Public routes */}
              <Route path="/" element={<LandingPage />} />
              <Route path="/login" element={<Login />} />
              <Route path="/register" element={<Register />} />
              <Route path="/forgot-password" element={<ForgotPassword />} />
              <Route path="/reset-password" element={<ResetPassword />} />
              <Route path="/onboarding" element={<OnboardingRoute />} />
              
              {/* Protected routes with strict validation */}
              <Route path="/admin" element={
                <PrivateRoute>
                  <AdminSandbox />
                </PrivateRoute>
              } />
              
              <Route path="/dashboard/*" element={
                <PrivateRoute>
                  <MainDashboard />
                </PrivateRoute>
              } />
              
              {/* Catch-all route with authentication validation */}
              <Route path="/*" element={<AppContent />} />
            </Routes>
          </ChatProvider>
        </AgentProvider>
      </OrchestratorProvider>
    </AuthProvider>
  );
}

export default App;