import React, { useEffect, useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';

const RouteGuard = ({ children }) => {
  const navigate = useNavigate();
  const location = useLocation();
  const { user, loading, performCompleteLogout } = useAuth();
  const [isChecking, setIsChecking] = useState(true);

  useEffect(() => {
    const checkAuthentication = () => {
      // Prevent access to protected routes if not authenticated
      if (!loading) {
        if (!user) {
          // Store the attempted location for redirect after login
          sessionStorage.setItem('redirectPath', location.pathname);
          performCompleteLogout();
          return;
        }

        // Check for valid authentication tokens
        const token = localStorage.getItem('access_token') || getCookie('access_token');
        if (!token) {
          console.warn('No valid authentication token found');
          performCompleteLogout();
          return;
        }

        // Check if token is expired (basic check)
        try {
          const payload = JSON.parse(atob(token.split('.')[1]));
          if (payload.exp * 1000 < Date.now()) {
            console.warn('Token expired');
            performCompleteLogout();
            return;
          }
        } catch (error) {
          console.warn('Invalid token format');
          performCompleteLogout();
          return;
        }
      }
      setIsChecking(false);
    };

    checkAuthentication();
  }, [user, loading, location.pathname, navigate, performCompleteLogout]);

  // Helper function to get cookie value
  const getCookie = (name) => {
    const value = `; ${document.cookie}`;
    const parts = value.split(`; ${name}=`);
    if (parts.length === 2) return parts.pop().split(';').shift();
    return null;
  };

  // Prevent browser back button access to protected routes after logout
  useEffect(() => {
    const handlePopState = (event) => {
      if (!user) {
        // Prevent going back to protected routes
        window.history.pushState(null, null, '/login');
        performCompleteLogout();
      }
    };

    // Add popstate listener for browser back button
    window.addEventListener('popstate', handlePopState);

    // Push current state to history stack
    if (user) {
      window.history.pushState({ user: true }, '', location.pathname);
    }

    return () => {
      window.removeEventListener('popstate', handlePopState);
    };
  }, [user, location.pathname, performCompleteLogout]);

  // Block navigation attempts when not authenticated
  useEffect(() => {
    const handleBeforeUnload = (event) => {
      if (!user && !loading) {
        // Prevent caching of protected pages
        event.preventDefault();
        event.returnValue = '';
      }
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => {
      window.removeEventListener('beforeunload', handleBeforeUnload);
    };
  }, [user, loading]);

  // Show loading spinner while checking authentication
  if (loading || isChecking) {
    return (
      <div className="auth-loading-container">
        <div className="auth-loading-spinner">
          <div className="spinner"></div>
          <p>Verifying authentication...</p>
        </div>
        <style jsx>{`
          .auth-loading-container {
            position: fixed;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: rgba(255, 255, 255, 0.95);
            display: flex;
            justify-content: center;
            align-items: center;
            z-index: 9999;
          }
          .auth-loading-spinner {
            text-align: center;
          }
          .spinner {
            border: 4px solid #f3f3f3;
            border-top: 4px solid #3498db;
            border-radius: 50%;
            width: 40px;
            height: 40px;
            animation: spin 1s linear infinite;
            margin: 0 auto 20px;
          }
          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
        `}</style>
      </div>
    );
  }

  // Render children only if authenticated
  return user ? children : null;
};

export default RouteGuard;
